<?php require_once "config/database.php"; require_once "includes/session.php"; include "includes/header.php";$products=$conn->query("SELECT * FROM products")->fetchAll(PDO::FETCH_ASSOC);?><div class="container"><h1 class="section-title">Shop</h1><div class="grid"><?php foreach($products as $p):?><div class="card"><img src="<?=e($p['image_url'])?>"><div class="card-body"><h3><?=e($p['product_name'])?></h3><p><?=e($p['description'])?></p><p>Stock: <?=$p['stock']?></p><div class="price">₱<?=number_format($p['price'],2)?></div><?php if(isLoggedIn()):?><form method="POST" action="cart.php"><input type="hidden" name="product_id" value="<?=$p['product_id']?>"><input type="number" name="quantity" value="1" min="1"><button name="add_to_cart" class="btn gold">Add to Cart</button></form><?php else:?><a class="btn" href="auth/login.php">Login to Buy</a><?php endif;?></div></div><?php endforeach;?></div></div><?php include "includes/footer.php";?>
